func TestPolicyQuotaController_CheckQuota(t *testing.T) {
	controller := NewPolicyQuotaController(nil, 5)

	testCases := []struct {
		name           string
		namespace      string
		initialCount   int
		shouldExceed   bool
		maxPerNs       int
	}{
		{
			name:         "quota not exceeded",
			namespace:    "default",
			initialCount: 3,
			shouldExceed: false,
			maxPerNs:     5,
		},
		{
			name:         "quota exactly at limit",
			namespace:    "default",
			initialCount: 5,
			shouldExceed: true,
			maxPerNs:     5,
		},
		{
			name:         "quota exceeded",
			namespace:    "default",
			initialCount: 6,
			shouldExceed: true,
			maxPerNs:     5,
		},
		{
			name:         "empty namespace should pass",
			namespace:    "test-ns",
			initialCount: 0,
			shouldExceed: false,
			maxPerNs:     5,
		},
