	if count := controller.getPolicyCount(namespace); count != 1 {
		t.Errorf("expected count 1, got %d", count)
	}

	controller.incrementPolicyCount(namespace)
	if count := controller.getPolicyCount(namespace); count != 2 {
		t.Errorf("expected count 2, got %d", count)
	}

	// Test decrementing
	controller.decrementPolicyCount(namespace)
	if count := controller.getPolicyCount(namespace); count != 1 {
		t.Errorf("expected count 1, got %d", count)
