func TestPolicyQuotaController_CheckQuota(t *testing.T) {
	controller := NewPolicyQuotaController(nil, 5)

	testCases := []struct {
		name           string
		namespace      string
		initialCount   int
		shouldExceed   bool
		maxPerNs       int
	}{
		{
			name:         "quota not exceeded",
			namespace:    "default",
			initialCount: 3,
			shouldExceed: false,
			maxPerNs:     5,
		},
		{
			name:         "quota exactly at limit",
			namespace:    "default",
			initialCount: 5,
			shouldExceed: true,
			maxPerNs:     5,
		},
		{
			name:         "quota exceeded",
			namespace:    "default",
			initialCount: 6,
			shouldExceed: true,
			maxPerNs:     5,
		},
		{
			name:         "empty namespace should pass",
			namespace:    "test-ns",
			initialCount: 0,
			shouldExceed: false,
			maxPerNs:     5,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			controller := NewPolicyQuotaController(nil, tc.maxPerNs)

			// Set initial count
			controller.mu.Lock()
			controller.policyCounts[tc.namespace] = tc.initialCount
			controller.mu.Unlock()

			err := controller.CheckQuota(tc.namespace)

			if tc.shouldExceed && err == nil {
				t.Errorf("expected error but got nil")
			}
			if !tc.shouldExceed && err != nil {
				t.Errorf("expected no error but got: %v", err)
			}
		})
	}
}

func TestPolicyQuotaController_IncrementDecrement(t *testing.T) {
	controller := NewPolicyQuotaController(nil, 10)

	namespace := "default"

	// Test incrementing
	controller.incrementPolicyCount(namespace)
	if count := controller.getPolicyCount(namespace); count != 1 {
		t.Errorf("expected count 1, got %d", count)
	}

	controller.incrementPolicyCount(namespace)
	if count := controller.getPolicyCount(namespace); count != 2 {
		t.Errorf("expected count 2, got %d", count)
	}

	// Test decrementing
	controller.decrementPolicyCount(namespace)
	if count := controller.getPolicyCount(namespace); count != 1 {
		t.Errorf("expected count 1, got %d", count)
	}

	controller.decrementPolicyCount(namespace)
	if count := controller.getPolicyCount(namespace); count != 0 {
		t.Errorf("expected count 0, got %d", count)
	}

	// Test that count doesn't go negative
	controller.decrementPolicyCount(namespace)
	if count := controller.getPolicyCount(namespace); count != 0 {
		t.Errorf("expected count 0, got %d", count)
	}
}

func TestPolicyQuotaController_GetNamespacePolicyCounts(t *testing.T) {
	controller := NewPolicyQuotaController(nil, 10)

	// Add some policy counts
	controller.incrementPolicyCount("ns1")
	controller.incrementPolicyCount("ns1")
	controller.incrementPolicyCount("ns2")

	counts := controller.GetNamespacePolicyCounts()

	if count, ok := counts["ns1"]; !ok || count != 2 {
		t.Errorf("expected ns1 count 2, got %d", count)
	}
	if count, ok := counts["ns2"]; !ok || count != 1 {
		t.Errorf("expected ns2 count 1, got %d", count)
	}

	// Verify that the returned map is a copy
	counts["ns1"] = 999
	if controller.getPolicyCount("ns1") != 2 {
		t.Error("modifying returned map affected controller state")
	}
}

func TestPolicyQuotaController_Run_WithMockStream(t *testing.T) {
	mockStream := &mockResourceStream{
		eventsChan: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy], 10),
	}

	controller := NewPolicyQuotaController(mockStream, 3)

	ctx, cancel := context.WithTimeout(context.Background(), 1*time.Second)
	defer cancel()

	// Create test policies
	policy1 := newTestPolicy("default", "policy1")
	policy2 := newTestPolicy("default", "policy2")
	policy3 := newTestPolicy("default", "policy3")

	// Simulate resource synchronization
	syncEvent := &mockEvent{
		kind:   resource.Sync,
		object: nil,
		key:    resource.Key{},
	}

	// Run the controller in a goroutine
	errChan := make(chan error, 1)
	go func() {
		errChan <- controller.Run(ctx)
	}()

	// Give the controller time to start listening
	time.Sleep(100 * time.Millisecond)

	// Send sync event
	mockStream.eventsChan <- syncEvent
	time.Sleep(50 * time.Millisecond)

	// Send upsert events
	upsertEvent1 := &mockEvent{
		kind:   resource.Upsert,
		object: policy1,
		key:    resource.Key{Name: "policy1", Namespace: "default"},
	}
	mockStream.eventsChan <- upsertEvent1
	time.Sleep(50 * time.Millisecond)

	// Verify count increased
	count := controller.getPolicyCount("default")
	if count != 1 {
		t.Errorf("expected count 1 after first upsert, got %d", count)
	}

	// Send another upsert
	upsertEvent2 := &mockEvent{
		kind:   resource.Upsert,
		object: policy2,
		key:    resource.Key{Name: "policy2", Namespace: "default"},
	}
	mockStream.eventsChan <- upsertEvent2
	time.Sleep(50 * time.Millisecond)

	count = controller.getPolicyCount("default")
	if count != 2 {
		t.Errorf("expected count 2 after second upsert, got %d", count)
	}

	// Send delete event
	deleteEvent := &mockEvent{
		kind:   resource.Delete,
		object: policy1,
		key:    resource.Key{Name: "policy1", Namespace: "default"},
	}
	mockStream.eventsChan <- deleteEvent
	time.Sleep(50 * time.Millisecond)

	count = controller.getPolicyCount("default")
	if count != 1 {
		t.Errorf("expected count 1 after delete, got %d", count)
	}

	// Cleanup
	cancel()
	time.Sleep(100 * time.Millisecond)
}

func TestPolicyQuotaController_ThreadSafety(t *testing.T) {
	controller := NewPolicyQuotaController(nil, 100)

	namespace := "default"

	// Run concurrent operations
	done := make(chan bool, 10)

	// Goroutines that increment
	for i := 0; i < 5; i++ {
		go func() {
			for j := 0; j < 10; j++ {
				controller.incrementPolicyCount(namespace)
			}
			done <- true
		}()
	}

	// Goroutines that check quota
	for i := 0; i < 5; i++ {
		go func() {
			for j := 0; j < 10; j++ {
				_ = controller.CheckQuota(namespace)
			}
			done <- true
		}()
	}

	// Wait for all goroutines to complete
	for i := 0; i < 10; i++ {
		<-done
	}

	// Verify final count
	expectedCount := 50 // 5 goroutines * 10 increments each
	count := controller.getPolicyCount(namespace)
	if count != expectedCount {
		t.Errorf("expected count %d, got %d", expectedCount, count)
	}
}
